import{_ as e,c as a,o as t,a4 as c}from"./chunks/framework.CC18aqI2.js";const u=JSON.parse('{"title":"Object","description":"","frontmatter":{},"headers":[],"relativePath":"article/basicJava/Object.md","filePath":"article/basicJava/Object.md","lastUpdated":null}'),s={name:"article/basicJava/Object.md"},o=c('<h1 id="object" tabindex="-1">Object <a class="header-anchor" href="#object" aria-label="Permalink to &quot;Object&quot;">​</a></h1><h2 id="_1-object简介" tabindex="-1">1.Object简介 <a class="header-anchor" href="#_1-object简介" aria-label="Permalink to &quot;1.Object简介&quot;">​</a></h2><p>Object是Java中最大的父类，所有的类都继承Object</p><p>Object中只有一个空参构造，没有有参构造，也没有任何成员变量</p><p>任何类中的任何方法，都默认会调用Object的无参构造</p><h2 id="_2-object成员方法" tabindex="-1">2.Object成员方法 <a class="header-anchor" href="#_2-object成员方法" aria-label="Permalink to &quot;2.Object成员方法&quot;">​</a></h2><h3 id="_2-1-tostring" tabindex="-1">2.1.toString() <a class="header-anchor" href="#_2-1-tostring" aria-label="Permalink to &quot;2.1.toString()&quot;">​</a></h3><p><img src="https://dazugipgkez.feishu.cn/space/api/box/stream/download/asynccode/?code=Mjc1NmE2MGYzMTU1ZDcwMzBmNDM0NjBiY2EzODM2YzNfQWJuZjd4ekNORjNKc2lTUTVSU0NzbmNuY0liM1NCT1hfVG9rZW46R0JzMGJ6M1Fwb2N0bkp4RW1nSmNyZGtKbnRiXzE3MjAzNjE1NjA6MTcyMDM2NTE2MF9WNA" alt="img"></p><p>上述代码的运行结果是<code>java.lang.Object@119d7047</code></p><p>以@为分界，前面是包名+类名，后面是对象的地址值(16进制)</p><p>直接用输出语句打印一个对象，打印的结果就是对象的字符串表示形式</p><h3 id="_2-2-equals" tabindex="-1">2.2.equals() <a class="header-anchor" href="#_2-2-equals" aria-label="Permalink to &quot;2.2.equals()&quot;">​</a></h3><p>直接调用Object里面的equals方法，默认比较的是地址值</p><p>如果想要更换比较规则，直接重写即可</p><p><img src="https://dazugipgkez.feishu.cn/space/api/box/stream/download/asynccode/?code=NjUyZjdhYzQwZDE0NGExOTI5NGM5MGYxNWNiOTE0NjlfaUJiM0NybXR5STh0WnVPTDBYam04VjhFRnRtdUYxTXpfVG9rZW46RW9Nb2JuQkxubzRXTDl4TDdzNWNhZGlEblpmXzE3MjAzNjE1NjA6MTcyMDM2NTE2MF9WNA" alt="img"></p><p>这串代码的输出结果是: false false</p><p>第一个<code>s.equals(sb)</code>调用者是s，是一个字符串对象，那么这里的equals就是String</p><p>类的equals，而String类的equals方法会先判断传递进来的参数是不是字符串，如果不是字符</p><p>串直接返回false，如果是字符串再比较两个字符串的内容</p><p>第二个<code>sb.equals(sb)</code>调用者是StringBuilder，但是StringBuilder根本没有equals，然后往</p><p>上看它的父类……只有它的最大父类Object中有equals方法，那么这里的equals方法就是</p><p>Object中的，也就是比较地址值</p><p>[未完结，待更新……✏️]</p>',23),i=[o];function l(r,p,d,n,b,h){return t(),a("div",null,i)}const _=e(s,[["render",l]]);export{u as __pageData,_ as default};
